-- Formalisable: countable criteria satisfaction
def MeetsThreeCriteria (ev : Evidence) : Prop := 
  ∃ (s : Finset (Fin 8)), s.card ≥ 3 ∧ ∀ i ∈ s, EvidenceFor ev (criterion i)

-- FormalisationBoundary: Open texture terms
@[FormalisationBoundary]
def ExtraordinaryAbility (p : Person) : DiscretionaryProp := 
  ⟨"sustained national/international acclaim", uscis_adjudicator, evidence_support⟩

-- Defeasible holding structure
def O1A_Eligibility (p : Person) : DefeasiblyHolds O1AVisa := 
  ⟨∃ ev, MeetsThreeCriteria ev ∧ ExtraordinaryAbility p ev, 
   [comparable_evidence_defeater]⟩
